local LFightIdleBaseCtrl = LXImport(".LFightIdleBaseCtrl")

---@class LFightIdleHurtCalc:LFightIdleBaseCtrl
local LFightIdleHurtCalc = LxClass("LFightIdleHurtCalc",LFightIdleBaseCtrl)
-----------------------------------------------------------------

---@type LAttrConst
local LAttrConst = LAttrConst



local LFightIdleHudData = LXImport("..Data.LFightIdleHudData")
-----------------------------------------------------------------
function LFightIdleHurtCalc:LFightIdleHurtCalc()

end

function LFightIdleHurtCalc:InitData(heroHitMonMap,monAttPerMap,missBlood)
	self._heroHitMonMap = heroHitMonMap
	self._monAttPerMap = monAttPerMap
	self._missBlood = missBlood
end

function LFightIdleHurtCalc:InitFloatData(floatHurtSplitList,floatHurtWaveMin,floatHurtWaveMax,floatHurtY,floatHurtTime,floatHurtXMin,floatHurtXMax)
	--飘字次数规则配置
	self._floatHurtSplitList = floatHurtSplitList
	--伤害波动随机范围 min
	self._floatHurtWaveMin = floatHurtWaveMin
	--伤害波动随机范围 max
	self._floatHurtWaveMax = floatHurtWaveMax
	--伤害数字相对Y
	self._floatHurtY = floatHurtY
	--伤害延迟时间
	self._floatHurtTime = floatHurtTime
	--伤害数字相对X min
	self._floatHurtXMin = floatHurtXMin
	--伤害数字相对X max
	self._floatHurtXMax = floatHurtXMax
end

function LFightIdleHurtCalc:CalcCrit(fromAttrData,toAttrData)
	local crit = fromAttrData[LAttrConst.Crit] or 0
	local defCrit = toAttrData[LAttrConst.DefCrit] or 0

	local rate = math.floor((crit -  defCrit) * 1000)

	local rand = math.random(1,1000)

	local bCrit = rand <= rate and rand >= 1

	return bCrit,(fromAttrData[LAttrConst.CritRatio] or 0)
end

function LFightIdleHurtCalc:GetCareerTypeAttrName(tCareerType)
	if tCareerType == 1 then
		return LAttrConst.AddHurt1
	elseif tCareerType == 2 then
		return LAttrConst.AddHurt2
	elseif tCareerType == 3 then
		return LAttrConst.AddHurt3
	elseif tCareerType == 4 then
		return LAttrConst.AddHurt4
	else
		return -1
	end
end

function LFightIdleHurtCalc:GetCareerAvoidHurtValue(tCareerType)
	local ref = GameTable.CharacterCareerRef[tCareerType]
	if ref then return ref.pAvoidHurtValue,ref.mAvoidHurtValue end
	return 0,0
end

---@param obj LFightIdleObject
---@param tarObj LFightIdleObject
function LFightIdleHurtCalc:CalcMagicHurt(skillRate,obj,tarObj)
	local fromAttrData = obj:GetAttrData()
	local toAttrData = tarObj:GetAttrData()
	local tCareerType = tarObj:GetCareerType()

	local mAvoidHurtValue= GameTable.BattleConfigRef["mAvoidHurtValue"] or 0
	local _,careerMAvoidHurtValue = self:GetCareerAvoidHurtValue(tCareerType)

	local atk = fromAttrData[LAttrConst.Atk] or 0
	if obj:GetObjType() == LFightIdleConst.OBJ_MON then
		atk = atk * (self._monAttPerMap[obj:GetQuality()] or 1)
	end

	local tDef = toAttrData[LAttrConst.Def] or 0

	local hurt = atk * (1 - tDef / (tDef + mAvoidHurtValue + tDef * careerMAvoidHurtValue))

	local addHurt = fromAttrData[LAttrConst.AddHurt] or 0
	local mHurt = fromAttrData[LAttrConst.MHurt] or 0
	local careerAddHurt = fromAttrData[self:GetCareerTypeAttrName(tCareerType)] or 0

	local tAvoidHurt = toAttrData[LAttrConst.AvoidHurt] or 0
	local tMAvoidHurt = toAttrData[LAttrConst.MAvoidHurt] or 0
	local skillHurt = hurt * skillRate * (1 + addHurt + mHurt + careerAddHurt - tAvoidHurt - tMAvoidHurt)

	return skillHurt
end

---@param obj LFightIdleObject
---@param tarObj LFightIdleObject
function LFightIdleHurtCalc:CalcPhysicsHurt(skillRate,obj,tarObj)
	local fromAttrData = obj:GetAttrData()
	local toAttrData = tarObj:GetAttrData()
	local tCareerType = tarObj:GetCareerType()

	local pAvoidHurtValue= GameTable.BattleConfigRef["pAvoidHurtValue"] or 0
	local careerPAvoidHurtValue,_ = self:GetCareerAvoidHurtValue(tCareerType)

	local atk = fromAttrData[LAttrConst.Atk] or 0
	if obj:GetObjType() == LFightIdleConst.OBJ_MON then
		atk = atk * (self._monAttPerMap[obj:GetQuality()] or 1)
	end

	local tDef = toAttrData[LAttrConst.Def] or 0

	local hurt = atk * (1 - tDef / (tDef + pAvoidHurtValue + tDef * careerPAvoidHurtValue))

	local addHurt = fromAttrData[LAttrConst.AddHurt] or 0
	local pHurt = fromAttrData[LAttrConst.PHurt] or 0
	local careerAddHurt = fromAttrData[self:GetCareerTypeAttrName(tCareerType)] or 0

	local tAvoidHurt = toAttrData[LAttrConst.AvoidHurt] or 0
	local tPAvoidHurt = toAttrData[LAttrConst.PAvoidHurt] or 0
	local skillHurt = hurt * skillRate * (1 + addHurt + pHurt + careerAddHurt - tAvoidHurt - tPAvoidHurt)
	return skillHurt
end

---@param obj LFightIdleObject
---@param tarObj LFightIdleObject
function LFightIdleHurtCalc:CalcSkillHurt(obj,tarObj,effectType,skillRate, bAlwaysCrit)
	local bCrit,critRatio = self:CalcCrit(obj:GetAttrData(),tarObj:GetAttrData())
	bAlwaysCrit = bAlwaysCrit and bAlwaysCrit or false
	bCrit = bAlwaysCrit or bCrit
	local skillHurt = 0
	if effectType == LFightIdleConst.CALC_EFFECT_PHYSICS then
		skillHurt = self:CalcPhysicsHurt(skillRate,obj,tarObj)
	else
		skillHurt = self:CalcMagicHurt(skillRate,obj,tarObj)
	end

	if bCrit then
		skillHurt = skillHurt * critRatio
	end
	skillHurt = Mathf.Floor(skillHurt)
	if skillHurt <= 0 then skillHurt = 1 end

	return skillHurt,bCrit
end


-----------------------------------------------------------------
---回复全部生命
---@param obj LFightIdleObject
function LFightIdleHurtCalc:RecoverHp(obj)
	local hpMax = obj:GetHpMax()
	local curHp = obj:GetCurHp()
	local addHp = Mathf.Floor(hpMax - curHp)
	if addHp <= 0 then return end

	obj:DoHurt(LFightIdleConst.HP_TYPE_HEAL,addHp)
	local hudCtrl = self:GetHudCtrl()
	hudCtrl:CreateHud(obj,{self:GenerateHudData(LFightIdleConst.HP_TYPE_HEAL,addHp,0,0,0,0)})
end

-----------------------------------------------------------------
---计算技能伤害
---@param obj LFightIdleObject
---@param tarObj LFightIdleObject
function LFightIdleHurtCalc:CalcHurt(obj,tarObj,skillData)
	local objType = obj:GetObjType()
	local tarObjType = tarObj:GetObjType()

	if objType == LFightIdleConst.OBJ_HERO and tarObjType == LFightIdleConst.OBJ_MON then
		self:CalcHeroHurtMon(obj,tarObj,skillData)
	elseif objType == LFightIdleConst.OBJ_MON and tarObjType == LFightIdleConst.OBJ_HERO then
		self:CalcMonHurtHero(obj,tarObj,skillData)
	end
end

---@param obj LFightIdleObject
---@param tarObj LFightIdleObject
function LFightIdleHurtCalc:CalcHeroHurtMon(obj,tarObj,skillData)
	local effectType = skillData.effectType
	local skillRate = skillData.skillRate

	local hurt,bCrit = self:CalcSkillHurt(obj,tarObj,effectType,skillRate, skillData.bAlwaysCrit)

	if not tarObj:IsInitHp() then
		local heroHitMon = self._heroHitMonMap[tarObj:GetQuality()] or {min=1,max=1}
		local minRand = math.floor(heroHitMon.min * 1000)
		local maxRand = math.floor(heroHitMon.max * 1000)
		local rand = math.random(minRand,maxRand) / 1000
		local maxHP = math.floor(hurt * rand)
		if maxHP <= 0 then maxHP = 1 end
		tarObj:InitHpData(maxHP)
	end

	local changeType = LFightIdleConst.HP_TYPE_HURT_MONSTER

	if bCrit then changeType = LFightIdleConst.HP_TYPE_CRIT end

	self:ApplyHurt(obj,tarObj,changeType,hurt,skillData)
end

---@param obj LFightIdleObject
---@param tarObj LFightIdleObject
function LFightIdleHurtCalc:CalcMonHurtHero(obj,tarObj,skillData)
	local maxHP = tarObj:GetHpMax()
	local curHp = Mathf.Floor(tarObj:GetCurHp())

	local missHp = Mathf.Floor(maxHP * self._missBlood)

	local effectType = skillData.effectType
	local skillRate = skillData.skillRate

	if curHp <= missHp then
		tarObj:DoHurt(LFightIdleConst.HP_TYPE_MISS,0)
		self:GetHudCtrl():CreateHud(tarObj,{self:GenerateHudData(LFightIdleConst.HP_TYPE_MISS,0,0,0,0,0)})
	else
		local hurt,bCrit = self:CalcSkillHurt(obj,tarObj,effectType,skillRate)
		local changeType = LFightIdleConst.HP_TYPE_HURT_HERO
		if bCrit then changeType = LFightIdleConst.HP_TYPE_CRIT end
		if (curHp - hurt) <= 0 then
			hurt = curHp - 1
		end
		self:ApplyHurt(obj,tarObj,changeType,hurt,skillData)
	end
end

function LFightIdleHurtCalc:GetHudCtrl()
	return self._manager:GetHudCtrl()
end

function LFightIdleHurtCalc:GetLogCtrl()
	return self._manager:GetLogCtrl()
end

-----------------------------------------------------------------
---执行技能伤害 飘字 被击 光效 播报等
---@param obj LFightIdleObject
---@param tarObj LFightIdleObject
function LFightIdleHurtCalc:ApplyHurt(obj,tarObj,changeType,hurt,skillData)
	local hudDataList = self:CalcHurtWaveData(changeType,hurt)
	tarObj:DoHurt(changeType,-hurt)
	if hurt > 0 then
		self:GetLogCtrl():LogHurt(obj,tarObj,hurt)
		self:GetHudCtrl():CreateHud(tarObj,hudDataList)
		if tarObj:IsLive() and tarObj:GetObjType() == LFightIdleConst.OBJ_MON then
			tarObj:GetAI():ChangeAction(LFightIdleConst.ACTION_BEHIT)
		end
	end
end

function LFightIdleHurtCalc:CalcHurtWaveData(changeType,hurt)
	local splitList = self._floatHurtSplitList
	local dataSplit = nil
	for k,v in ipairs(splitList) do
		if hurt <= v.limitVal then
			break
		end
		dataSplit = v
	end
	if not dataSplit then
		return {self:GenerateHudData(changeType,hurt,0,0,0,0)}
	end
	local splitMix = dataSplit.min
	local splitMax = dataSplit.max
	local nWave = LFightIdleConst.RandInteger(splitMax - splitMix + 1) + (splitMix - 1)
	if nWave <= 1 then
		return {self:GenerateHudData(changeType,hurt,0,0,0,0)}
	end

	local averageHurt = math.floor(hurt / nWave)

	local floatHurtY = self._floatHurtY
	local floatHurtXMin = self._floatHurtXMin
	local floatHurtXMax = self._floatHurtXMax

	local floatHurtTime = self._floatHurtTime
	local minWaveRate = self._floatHurtWaveMin
	local maxWaveRate = self._floatHurtWaveMax
	local nowHurt = 0
	local hurtDataList = {}
	for k=1,nWave-1 do
		local hurtRate = (math.random() * (maxWaveRate - minWaveRate) + minWaveRate)
		local oneHurt = math.floor(averageHurt * hurtRate)
		local tmpHurtTotal = nowHurt + oneHurt
		if tmpHurtTotal >= hurt then
			break
		end
		nowHurt = tmpHurtTotal
		table.insert(hurtDataList,self:GenerateHudData(changeType,oneHurt,floatHurtTime * (k-1),floatHurtY,floatHurtXMin,floatHurtXMax))
	end

	if nowHurt < hurt then
		table.insert(hurtDataList,self:GenerateHudData(changeType,hurt - nowHurt,floatHurtTime * (#hurtDataList-1),floatHurtY,floatHurtXMin,floatHurtXMax))
	end
	return hurtDataList
end

-----------------------------------------------------------------
---组织 飘字数据结构
function LFightIdleHurtCalc:GenerateHudData(changeType,hurt,delay,floatHurtY,floatHurtXMin,floatHurtXMax)
	return LFightIdleHudData:New(changeType,hurt,delay,floatHurtY,floatHurtXMin,floatHurtXMax)
end


